namespace sv_5044ce07e24b4628b6c587bcee1dd9e6.Services;

public record WarehouseInfo(string Id, string Name);

/// <summary>
/// Scoped per circuit — each user gets their own independent warehouse selection.
/// </summary>
public sealed class WarehouseState
{
    public static readonly IReadOnlyList<WarehouseInfo> AvailableWarehouses =
    [
        new("WH-001", "Warehouse A – Downtown"),
        new("WH-002", "Warehouse B – Airport"),
        new("WH-003", "Warehouse C – Harbor"),
    ];

    private string _currentWarehouseId = AvailableWarehouses[0].Id;

    public string CurrentWarehouseId
    {
        get => _currentWarehouseId;
        set
        {
            if (_currentWarehouseId != value)
            {
                _currentWarehouseId = value;
                OnChange?.Invoke();
            }
        }
    }

    public string CurrentWarehouseName =>
        AvailableWarehouses.FirstOrDefault(w => w.Id == _currentWarehouseId)?.Name ?? "Unknown";

    public event Action? OnChange;
}

namespace sv_5044ce07e24b4628b6c587bcee1dd9e6.Services;

/// <summary>
/// Simulates a database query for low-stock items in a warehouse.
/// </summary>
public sealed class InventoryAlertService
{
    private readonly Random _random = new();

    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulate a database call returning 0-15 low-stock items.
        return Task.FromResult(_random.Next(0, 16));
    }
}

