@page "/dashboard"
@rendermode InteractiveServer
@using sv_5044ce07e24b4628b6c587bcee1dd9e6.Services
@inject WarehouseState WarehouseState
@inject InventoryAlertService AlertService
@inject InventoryAlertState AlertState
@implements IDisposable

<PageTitle>Dashboard – @WarehouseState.CurrentWarehouseName</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mb-4">
    <div class="card-body">
        <h5 class="card-title">@WarehouseState.CurrentWarehouseName</h5>
        <p class="card-text text-muted">Site ID: @WarehouseState.CurrentWarehouseId</p>
    </div>
</div>

<div class="row g-4">
    <div class="col-md-4">
        <div class="card text-bg-@(AlertState.LowStockCount > 0 ? "danger" : "success")">
            <div class="card-body text-center">
                <h2 class="display-4">@AlertState.LowStockCount</h2>
                <p class="card-text">Low-Stock Alerts</p>
                <small class="opacity-75">Refreshes every 10 s</small>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card text-bg-info">
            <div class="card-body text-center">
                <h2 class="display-4">—</h2>
                <p class="card-text">Pending Shipments</p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card text-bg-secondary">
            <div class="card-body text-center">
                <h2 class="display-4">—</h2>
                <p class="card-text">Items Received Today</p>
            </div>
        </div>
    </div>
</div>

@code {
    private CancellationTokenSource? _cts;

    protected override async Task OnInitializedAsync()
    {
        WarehouseState.OnChange += OnWarehouseChanged;
        await PollOnceAsync();
        StartPolling();
    }

    private void OnWarehouseChanged()
    {
        // Restart polling for the newly selected warehouse.
        StopPolling();
        InvokeAsync(async () =>
        {
            await PollOnceAsync();
            StateHasChanged();
            StartPolling();
        });
    }

    private void StartPolling()
    {
        _cts = new CancellationTokenSource();
        _ = PollLoopAsync(_cts.Token);
    }

    private void StopPolling()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(10), ct);
                await PollOnceAsync();
                await InvokeAsync(StateHasChanged);
            }
            catch (OperationCanceledException)
            {
                break;
            }
        }
    }

    private async Task PollOnceAsync()
    {
        var count = await AlertService.GetLowStockCountAsync(WarehouseState.CurrentWarehouseId);
        AlertState.UpdateCount(count);
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= OnWarehouseChanged;
        StopPolling();
    }
}

